import java.util.Scanner;

public class TryCatchExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        try {
            System.out.print("Enter a number: ");
            int num = scanner.nextInt();

            int result = 100 / num;
            System.out.println("Result: " + result);

            // This might cause an exception if string is invalid
            int[] arr = {1, 2, 3};
            System.out.println("Array[5]: " + arr[5]);

        } catch (ArithmeticException e) {
            // Catches division by zero
            System.out.println("Error: Cannot divide by zero!");
            System.out.println("Message: " + e.getMessage());

        } catch (ArrayIndexOutOfBoundsException e) {
            // Catches invalid array index
            System.out.println("Error: Array index out of bounds!");
            System.out.println("Message: " + e.getMessage());

        } catch (Exception e) {
            // Catches ANY other exception (should be last)
            System.out.println("Error: Something went wrong!");
            System.out.println("Message: " + e.getMessage());

        } finally {
            // Always runs — even if exception occurs
            System.out.println("Finally block: Cleanup code here!");
            scanner.close();
        }

        System.out.println("Program continues...");
    }
}

